const { Problem } = require('../models');

async function solve({ includeComponents = false, limit = 50, difficulty, tags }) {
  // Build base query with filters
  let query = Problem.query();

  if (difficulty) {
    query = query.where('difficulty', difficulty);
  }

  if (tags && tags.length > 0) {
    query = query.whereRaw('tags && ?', [tags]);
  }

  // Apply limit before aggregation
  const problems = await query.limit(limit);

  // Prepare metadata object
  const metadata = {};

  if (includeComponents) {
    // Aggregate componentLanguageTotals and componentStatusTotals on filtered+limited problems
    const componentLanguageTotals = {};
    const componentStatusTotals = {};

    for (const problem of problems) {
      // Deduplicate and sort componentLanguages case-insensitively
      const uniqueLanguages = [...new Set(
        (problem.componentLanguages || []).map(lang => lang.toLowerCase())
      )].sort((a, b) => a.localeCompare(b));

      for (const lang of uniqueLanguages) {
        componentLanguageTotals[lang] = (componentLanguageTotals[lang] || 0) + 1;
      }

      for (const status of problem.componentStatuses || []) {
        componentStatusTotals[status] = (componentStatusTotals[status] || 0) + 1;
      }
    }

    metadata.componentLanguageTotals = componentLanguageTotals;
    metadata.componentStatusTotals = componentStatusTotals;
  }

  return { problems, metadata };
}

module.exports = { solve };
